-- TheOneGoofAli was here.
-- This is a loading screen replacement script that is meant for a Lovely patch copy
-- and should not be normally loaded under other circumstances anyway.

-- Larger image equals larger string.
local wormhole_loadimg = {
	"",
	""
}

-- Different drawing time.
local btref = boot_timer
function boot_timer(_label, _next, progress)
	progress = progress or 0
	G.LOADING = G.LOADING or {
		font = love.graphics.setNewFont("resources/fonts/m6x11plus.ttf", 20),
		love.graphics.dis
	}
	if not wormholeimg then wormholeimg = love.graphics.newImage(love.data.decode("data", "base64", wormhole_loadimg[math.random(1, 2) or 1]), { mipmaps = true, linear = true }) end
	if wormholeimg then
		local realw, realh = love.window.getMode()
		local pbarl, pbarh = 320, 30
		local pbarx, pbary = realw / 2 - 120 - 40, realh / 2 + 116
		love.graphics.setCanvas()
		love.graphics.push()
		love.graphics.setShader()
		love.graphics.clear(0, 0, 0, 1)
		love.graphics.setColor(1, 1, 1, 1)
		love.graphics.draw(wormholeimg, realw/2 - 320, realh/2 - 180, 0, 1, 1)
		love.graphics.setColor(0.6, 0.8, 0.9, 1)
		if progress > 0 then love.graphics.rectangle('fill', pbarx, pbary, progress * pbarl, pbarh, 5) end
		love.graphics.setColor(1, 1, 1, 1)
		love.graphics.setLineWidth(3)
		love.graphics.rectangle('line', pbarx, pbary, pbarl, pbarh, 5)
		love.graphics.printf("POTATO PATCH - [PROJECT WORMHOLE]", pbarx - 160, pbary + 40, 640, 'center')
		love.graphics.printf("" .. _next, pbarx - 160, pbary + 64, 640, 'center')
		love.graphics.pop()
		love.graphics.present()

		G.ARGS.bt = G.ARGS.bt or love.timer.getTime()
		G.ARGS.bt = love.timer.getTime()
	else
		btref(_label, _next, progress)
	end
end
